public class SessionManager
{
    private readonly string _sessionDirectory;
    private readonly BinaryFormatter _formatter;
    private readonly int _sessionExpirationMinutes;

    public SessionManager(string sessionDirectory = "Sessions", int sessionExpirationMinutes = 30)
    {
        _sessionDirectory = sessionDirectory;
        _sessionExpirationMinutes = sessionExpirationMinutes;
        _formatter = new BinaryFormatter();

        if (!Directory.Exists(_sessionDirectory))
        {
            Directory.CreateDirectory(_sessionDirectory);
        }
    }

    private string GetSessionFilePath(string sessionId)
    {
        return Path.Combine(_sessionDirectory, $"{sessionId}.session");
    }

    public UserSession CreateSession(string userId)
    {
        var session = new UserSession(userId);
        SaveSession(session);
        return session;
    }

    public void SaveSession(UserSession session)
    {
        session.UpdateLastAccessed();
        string filePath = GetSessionFilePath(session.SessionId);

        using (FileStream fs = new FileStream(filePath, FileMode.Create))
        {
            _formatter.Serialize(fs, session);
        }
    }

    public UserSession LoadSession(string sessionId)
    {
        string filePath = GetSessionFilePath(sessionId);

        if (!File.Exists(filePath))
        {
            return null;
        }

        UserSession session;
        using (FileStream fs = new FileStream(filePath, FileMode.Open))
        {
            session = (UserSession)_formatter.Deserialize(fs);
        }

        if (session.IsExpired(_sessionExpirationMinutes))
        {
            DeleteSession(sessionId);
            return null;
        }

        session.UpdateLastAccessed();
        SaveSession(session);
        return session;
    }

    public void DeleteSession(string sessionId)
    {
        string filePath = GetSessionFilePath(sessionId);
        if (File.Exists(filePath))
        {
            File.Delete(filePath);
        }
    }

    public void CleanupExpiredSessions()
    {
        var sessionFiles = Directory.GetFiles(_sessionDirectory, "*.session");

        foreach (var filePath in sessionFiles)
        {
            try
            {
                UserSession session;
                using (FileStream fs = new FileStream(filePath, FileMode.Open))
                {
                    session = (UserSession)_formatter.Deserialize(fs);
                }

                if (session.IsExpired(_sessionExpirationMinutes))
                {
                    File.Delete(filePath);
                }
            }
            catch
            {
                File.Delete(filePath);
            }
        }
    }

    public List<UserSession> GetAllActiveSessions()
    {
        var activeSessions = new List<UserSession>();
        var sessionFiles = Directory.GetFiles(_sessionDirectory, "*.session");

        foreach (var filePath in sessionFiles)
        {
            try
            {
                UserSession session;
                using (FileStream fs = new FileStream(filePath, FileMode.Open))
                {
                    session = (UserSession)_formatter.Deserialize(fs);
                }

                if (!session.IsExpired(_sessionExpirationMinutes))
                {
                    activeSessions.Add(session);
                }
            }
            catch
            {
            }
        }

        return activeSessions;
    }

    public UserSession GetSessionByUserId(string userId)
    {
        var sessions = GetAllActiveSessions();
        return sessions.Find(s => s.UserId == userId);
    }

    public bool SessionExists(string sessionId)
    {
        return File.Exists(GetSessionFilePath(sessionId));
    }

    public void DeleteAllSessions()
    {
        var sessionFiles = Directory.GetFiles(_sessionDirectory, "*.session");
        foreach (var filePath in sessionFiles)
        {
            File.Delete(filePath);
        }
    }

    public int GetActiveSessionCount()
    {
        return GetAllActiveSessions().Count;
    }
}

